eventOn('mag_variable_update_ended', variableUpdateEnded);
let last_date = "";
let is_day_passed = false;
function parseTimeToNumber(timeStr) {
    const [hours, minutes] = timeStr.split(':').map(Number);
    return hours * 100 + (minutes || 0);
}
function variableUpdateStarted(variables, out_is_updated) {
    last_date = variables.stat_data.Thời_Gian[0];
    is_day_passed = false;
    out_is_updated = out_is_updated || false;
}
function variableUpdated(_stat_data, path, _oldValue, _newValue) {
    if (path == '时间') {
        const timeNumber = parseTimeToNumber(_newValue);
        const oldTime = parseTimeToNumber(_oldValue);
        //当时间变小时，就代表新的一天来临了
        if (timeNumber < oldTime) {
            is_day_passed = true;
        }
    }
}
/**
 * 计算下一天的Thời_Gian
 * @param dateStr Thời_Gian字符串，格式为"NgàyDDThángMM"，例如"Ngày1Tháng1"
 * @returns 下一天的Thời_Gian字符串，保持相同格式
 */
function nextDate(dateStr) {
    // 移除末尾的"Ngày"字，并分割Tháng份和Thời_Gian
    const [month, day] = dateStr.replace('Ngày', '').split('Tháng');
    let nextMonth = parseInt(month);
    let nextDay = parseInt(day);
    nextDay++;
    const daysInMonth = [31, 31, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    if (nextDay > daysInMonth[nextMonth - 1]) {
        nextDay = 1;
        nextMonth++;
        if (nextMonth > 12) {
            nextMonth = 1;
        }
    }
    // 返回时需要加上"Ngày"后缀
    return `Ngày${nextDay}Tháng${nextMonth}`;
}
function variableUpdateEnded(variables, out_is_updated) {
    if (!is_day_passed)
        return;
    if (variables.stat_data.Thời_Gian[0] == last_date) {
        // Thời_Gian字符串必须包含"Ngày"字作为后缀，例如"Ngày1Tháng1"
        //llm 没有自动推进Thời_Gian，通过代码辅助他推进
        var new_date = nextDate(last_date);
        variables.stat_data.Thời_Gian[0] = new_date;
        const display_str = `${last_date}->${new_date}(Thời_Gian推进)`;
        variables.display_data.Thời_Gian = display_str;
        out_is_updated = true;
    }
    out_is_updated = out_is_updated || false;
}

