        // --- DATA HANDLING & UPDATES (with retry mechanism) ---
        let retryCount = 0;
        const MAX_RETRIES = 5;

        async function fetchDataAndUpdateUI() {
            try {
                if (typeof getCurrentMessageId !== 'function' || typeof getChatMessages !== 'function') {
                    console.error("SillyTavern API functions not found.");
                    updateFromInjectedText();
                    return;
                }
                const msgId = getCurrentMessageId();
                const messages = await getChatMessages(msgId);

                if (messages && messages.length > 0 && messages[0].data && messages[0].data.stat_data) {
                    const statData = messages[0].data.stat_data;
                    updateDisplays(statData);
                    retryCount = 0;
                } else {
                    if (retryCount < MAX_RETRIES) {
                        retryCount++;
                        console.warn(`stat_data not found. Retry ${retryCount}/${MAX_RETRIES} in 300ms...`);
                        setTimeout(fetchDataAndUpdateUI, 300);
                    } else {
                        console.error("Max retries reached. Failed to fetch stat_data.");
                    }
                }
            } catch (error) {
                console.error("Error fetching data:", error);
            }
            updateFromInjectedText();
            setTimeout(() => window.dispatchEvent(new Event('resize')), 150);
        }

        function updateDisplays(statData) {
            const worldData = statData.Thế_Giới || {};
            updateElementText('game-location', `📍 ${worldData.Địa_Điểm ? worldData.Địa_Điểm[0] : '--'}`);
            updateElementText('game-date', `📅 ${worldData.Ngày_Tháng ? worldData.Ngày_Tháng[0] : '--'}`);
            updateElementText('game-time', `⏳ ${worldData.Thời_Gian ? worldData.Thời_Gian[0] : '--'}`);

            let firstActiveCharacter = null;
            let activeCharacterFound = false;

            CHARACTERS.forEach(name => {
                const charData = statData[name];
                const tabButton = document.querySelector(`.tab-button[data-char-name="${name}"]`);

                if (charData && tabButton) {
                    const isActive = charData.Trạng_Thái_Xuất_Hiện && charData.Trạng_Thái_Xuất_Hiện[0] === 'Xuất hiện';

                    tabButton.style.display = isActive ? '' : 'none';

                    if (isActive) {
                        activeCharacterFound = true;
                        if (!firstActiveCharacter) {
                            firstActiveCharacter = name;
                        }

                        // Chỉ cập nhật dữ liệu chi tiết khi nhân vật đang hoạt động
                        updateElementText(`${name}-Đọa_Lạc`, charData.Đọa_Lạc ? charData.Đọa_Lạc[0] : '0');
                        updateProgressBar(`${name}-Đọa_Lạc-bar`, charData.Đọa_Lạc ? charData.Đọa_Lạc[0] : 0, 0, 100);
                        updateElementText(`${name}-Lý_Do_Cập_Nhật_Đọa_Lạc`, charData.Lý_Do_Cập_Nhật_Đọa_Lạc ? charData.Lý_Do_Cập_Nhật_Đọa_Lạc[0] : '--');
                        updateElementText(`${name}-Nghề_Nghiệp`, charData.Nghề_Nghiệp ? charData.Nghề_Nghiệp[0] : '--');
                        updateTaskProgressBar(`${name}-Tiến_Độ_Hoàn_Thành_Nhiệm_Vụ`, `${name}-Tiến_Độ_Hoàn_Thành_Nhiệm_Vụ-bar`, charData.Tiến_Độ_Hoàn_Thành_Nhiệm_Vụ ? charData.Tiến_Độ_Hoàn_Thành_Nhiệm_Vụ[0] : '--');
                        updateElementText(`${name}-Thần_Thái`, charData.Thần_Thái ? charData.Thần_Thái[0] : '--');
                        updateElementText(`${name}-Tư_Thế`, charData.Tư_Thế ? charData.Tư_Thế[0] : '--');
                        updateElementText(`${name}-Suy_Nghĩ_Nội_Tâm`, charData.Suy_Nghĩ_Nội_Tâm ? charData.Suy_Nghĩ_Nội_Tâm[0] : '--');
                    }
                } else if (tabButton) {
                    tabButton.style.display = 'none'; 
                }
            });

            // Đảm bảo có một tab được chọn
            const currentActiveTab = document.querySelector('.tab-button.active');
            if (firstActiveCharacter && (!currentActiveTab || currentActiveTab.style.display === 'none')) {
                showTab(firstActiveCharacter);
            } else if (!activeCharacterFound && currentActiveTab) {
                // Nếu không có nhân vật nào xuất hiện, ẩn tất cả nội dung
                currentActiveTab.classList.remove('active');
                document.querySelectorAll('.tab-content').forEach(tc => tc.classList.remove('active'));
            }
        }

        function updateFromInjectedText() {
            const dataContainer = document.getElementById('injected-data-container');
            if (!dataContainer) return;
            const rawText = dataContainer.textContent || "";

            const mainContentMatch = rawText.match(/<maincontent>([\s\S]*?)<\/maincontent>/i);
            const mainContentEl = document.getElementById('main-content-text');
            if (mainContentMatch && mainContentEl) {
                mainContentEl.innerHTML = mainContentMatch[1].trim();
                formatSpecialText(mainContentEl);
