            const optionsMatch = rawText.match(/<option>([\s\S]*?)<\/option>/i);
            const choicesContainer = document.getElementById('choices-container');
            if (optionsMatch && choicesContainer) {
                const optionsText = optionsMatch[1].trim();
                const optionLines = optionsText.split('\n').filter(line => line.trim() !== '');
                choicesContainer.innerHTML = '';
                optionLines.forEach(line => {
                    const choiceDiv = document.createElement('div');
                    choiceDiv.className = 'choice-item';
                    choiceDiv.textContent = line.trim();
                    choiceDiv.onclick = () => {
                         if (typeof triggerSlash === 'function') {
                             try { triggerSlash(`/send ${line.trim()} | /trigger await=true`); } 
                             catch (e) { alert(`Gửi lệnh thất bại, vui lòng sao chép thủ công:\n${line.trim()}`); }
                         } else { alert(`Không thể gửi tự động, vui lòng sao chép thủ công:\n${line.trim()}`); }
                    };
                    choicesContainer.appendChild(choiceDiv);
                });
            } else if (choicesContainer) {
                choicesContainer.innerHTML = `<div class="choice-item">Hiện không có lựa chọn nào, mời tự do hành động...</div>`;
            }
        }

        // --- HELPER FUNCTIONS ---
        function updateElementText(id, text) { const el = document.getElementById(id); if (el) el.innerHTML = text; }

        function updateProgressBar(barId, value, min, max) {
            const bar = document.getElementById(barId);
            if (!bar) return;
            const numValue = parseFloat(value) || 0;
            const percentage = (max > min) ? Math.max(0, Math.min(100, ((numValue - min) / (max - min)) * 100)) : 0;
            bar.style.width = `${percentage}%`;
        }

        function updateTaskProgressBar(textId, barId, valueString) {
            const textEl = document.getElementById(textId);
            const barEl = document.getElementById(barId);
            if (!textEl || !barEl) return;
            textEl.textContent = valueString;
            const matches = valueString.match(/:\s*([\d.]+)\/([\d.]+)/);
            if (matches && matches.length === 3) {
                const current = parseFloat(matches[1]);
                const total = parseFloat(matches[2]);
                updateProgressBar(barId, current, 0, total);
            } else {
                barEl.style.width = '0%';
            }
        }

        function showTab(charName) {
            document.querySelectorAll('.tab-content').forEach(tc => tc.classList.remove('active'));
            document.querySelectorAll('.tab-button').forEach(tb => tb.classList.remove('active'));
            const contentEl = document.getElementById(`${charName}-tab-content`);
            const buttonEl = document.querySelector(`.tab-button[data-char-name="${charName}"]`);
            if (contentEl) contentEl.classList.add('active');
            if (buttonEl) buttonEl.classList.add('active');
        }

        function formatSpecialText(element) {
            const formattingRegex = /“([^”]+)”|"([^"]+)"|「([^」]+)」|『([^』]+)』|\*([^*]+)\*/g;
            element.innerHTML = element.innerHTML.replace(formattingRegex, (match, cq, eq, cj1, cj2, thought) => {
                if (thought) return `<span class="thought-text">*${thought}*</span>`;
                const dialog = cq || eq || cj1 || cj2;
                if (dialog) return `<span class="dialog-text">${match}</span>`;
                return match;
            });
        }

        function setupPalette() {
            const paletteButton = document.querySelector('.palette-button');
            const paletteModal = document.querySelector('.palette-modal');
            const closeButton = document.querySelector('.palette-close');
            const themeSelect = document.getElementById('theme-select');

            const applyTheme = (themeName) => {
                const theme = THEMES[themeName];
                if (!theme) return;
                for (const [key, value] of Object.entries(theme)) {
                    document.documentElement.style.setProperty(key, value);
                }
                localStorage.setItem('goddess_corruption_theme', themeName);
            };

            paletteButton.onclick = (event) => { event.stopPropagation(); paletteModal.classList.toggle('show'); };
            closeButton.onclick = () => paletteModal.classList.remove('show');
            document.addEventListener('click', (event) => {
                if (!paletteModal.contains(event.target) && !paletteButton.contains(event.target)) {
                    paletteModal.classList.remove('show');
                }
            });
            themeSelect.onchange = (e) => applyTheme(e.target.value);

            const savedTheme = localStorage.getItem('goddess_corruption_theme');
            if (savedTheme && THEMES[savedTheme]) {
                themeSelect.value = savedTheme;
                applyTheme(savedTheme);
            } else {
                applyTheme('goddess_corruption');
            }
        }

        if (document.readyState === 'complete' || document.readyState === 'interactive') {
            initializeUI();
        } else {
            document.addEventListener('DOMContentLoaded', initializeUI);
        }
    })();
    </script>
</body>
